queries.text:
RawEventsTraces
| where TimeGenerated between (_startTime .. _endTime)
// Command-completion rows. The new stable Message is "dotnetup/command" with the
// subcommand carried in the command.name property. The legacy per-subcommand
// fan-out ("dotnetup/command/<sub>") is kept so dashboards keep rendering
// historical data through the cutover and can be removed once aged out.
| where Message == "dotnetup/command" or Message startswith "dotnetup/command/"
| extend is_dev = tobool(Properties["dev.build"])
| extend version = tostring(Properties["dotnetup.version"])
| extend command = coalesce(tostring(Properties["command.name"]), substring(Message, strlen("dotnetup/command/"), 256))
| extend error_category = tostring(Properties["error.category"])
| extend error_type = tostring(Properties["error.type"])
| extend exit_code = tostring(Properties["exit.code"])
| extend command_status = tostring(Properties["command.status"])
// A command run is successful when the process exited 0 AND no error was
// attached to the activity chain. Older rows without exit.code fall back to
// command.status ("ok"/"error") set via TrackedOperation.SetStatus.
| extend is_success = isempty(error_type) and iif(isnotempty(exit_code), exit_code == "0", command_status == "ok")
| extend duration_ms = todouble(Properties["operation.duration_ms"])
| where (isempty(_versionFilter) or version == _versionFilter)
| where (isempty(['_devBuild']) or is_dev == tobool(['_devBuild']))
